package edu.rice.comp322.boruvka.parallel;

import edu.rice.comp322.AbstractBoruvka;
import edu.rice.comp322.boruvka.BoruvkaFactory;
import edu.rice.comp322.boruvka.Edge;
import edu.rice.comp322.boruvka.Loader;
import edu.rice.hj.api.SuspendableException;

import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;
import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;
import java.util.concurrent.TimeUnit;

/**
 * This class must be modified.
 *
 * @author <a href="http://shams.web.rice.edu/">Shams Imam</a> (shams@rice.edu)
 */
public final class ParBoruvka extends AbstractBoruvka implements BoruvkaFactory<ParComponent, ParEdge> {

    protected final Queue<ParComponent> nodesLoaded = new LinkedList<>();
    protected final List<ParComponent> allNodes = new ArrayList<>();

    public ParBoruvka() {
        super();
    }

    @Override
    public boolean usesHjLib() {
        return true;
    }

    @Override
    public void initialize(final String[] args) {
        Loader.parseArgs(args);
    }

    @Override
    public void preIteration(final int iterationIndex) {
        // Exclude reading file input from timing measurement
        nodesLoaded.clear();
        Loader.read(this, nodesLoaded);
        allNodes.clear();
        allNodes.addAll(nodesLoaded);

        totalEdges = 0;
        totalWeight = 0;
    }

    @Override
    public void runIteration(int nthreads) throws SuspendableException {
        if (nthreads <= 1) {
            computeBoruvkaSequential(nodesLoaded);
        } else {
            computeBoruvkaParallel(nodesLoaded, nthreads);
        }
    }

    private void computeBoruvkaSequential(final Queue<ParComponent> nodesLoaded) {

        ParComponent loopNode = null;

        // START OF EDGE CONTRACTION ALGORITHM
        while (!nodesLoaded.isEmpty()) {

            // poll() removes first element (node loopNode) from the nodesLoaded work-list
            loopNode = nodesLoaded.poll();

            if (loopNode.isDead) {
                continue; // node loopNode has already been merged
            }

            final Edge<ParComponent> e = loopNode.getMinEdge(); // retrieve loopNode's edge with minimum cost
            if (e == null) {
                break; // done - we've contracted the graph to a single node
            }

            final ParComponent other = e.getOther(loopNode);
            other.isDead = true;
            loopNode.merge(other, e.weight()); // merge node other into node loopNode
            nodesLoaded.add(loopNode); // add newly merged loopNode back in the work-list

        }
        // END OF EDGE CONTRACTION ALGORITHM
        if (loopNode != null) {
            totalEdges = loopNode.totalEdges();
            totalWeight = loopNode.totalWeight();
        }
    }

    private void computeBoruvkaParallel(final Queue<ParComponent> initialNodesLoaded, final int nthreads) {
        final ConcurrentLinkedQueue<ParComponent> workQueue = new ConcurrentLinkedQueue<>(initialNodesLoaded);
        final ExecutorService executor = Executors.newFixedThreadPool(nthreads);

        try {
            while (!workQueue.isEmpty()) {
                final List<ParComponent> batch = new ArrayList<>();
                ParComponent loopNode;
                while ((loopNode = workQueue.poll()) != null) {
                    batch.add(loopNode);
                }
                if (batch.isEmpty()) {
                    continue;
                }

                final int chunkSize = Math.max(1, (batch.size() + nthreads - 1) / nthreads);
                final List<Future<?>> futures = new ArrayList<>();
                for (int start = 0; start < batch.size(); start += chunkSize) {
                    final int from = start;
                    final int to = Math.min(batch.size(), start + chunkSize);
                    futures.add(executor.submit(() -> {
                        for (int i = from; i < to; i++) {
                            processComponent(batch.get(i), workQueue);
                        }
                    }));
                }

                for (Future<?> future : futures) {
                    try {
                        future.get();
                    } catch (Exception e) {
                        throw new RuntimeException(e);
                    }
                }
            }
        } finally {
            executor.shutdown();
        }
        try {
            executor.awaitTermination(1, TimeUnit.HOURS);
        } catch (InterruptedException ie) {
            Thread.currentThread().interrupt();
            throw new RuntimeException(ie);
        }

        ParComponent root = null;
        for (ParComponent c : allNodes) {
            if (!c.isDead) {
                root = c;
                break;
            }
        }

        if (root != null) {
            totalEdges = root.totalEdges();
            totalWeight = root.totalWeight();
        }
    }

    private void processComponent(final ParComponent loopNode, final ConcurrentLinkedQueue<ParComponent> workQueue) {
        if (loopNode.isDead) {
            return;
        }

        if (!loopNode.lock.tryLock()) {
            workQueue.offer(loopNode);
            return;
        }

        try {
            if (loopNode.isDead) {
                return;
            }

            final Edge<ParComponent> edge = loopNode.getMinEdge();
            if (edge == null) {
                return;
            }

            final ParComponent other = edge.getOther(loopNode);
            if (other == loopNode) {
                return;
            }

            if (!other.lock.tryLock()) {
                workQueue.offer(loopNode);
                return;
            }

            try {
                if (loopNode.isDead) {
                    if (!other.isDead) {
                        workQueue.offer(other);
                    }
                    return;
                }
                if (other.isDead) {
                    workQueue.offer(loopNode);
                    return;
                }

                other.isDead = true;
                loopNode.merge(other, edge.weight());
                workQueue.offer(loopNode);
            } finally {
                other.lock.unlock();
            }
        } finally {
            loopNode.lock.unlock();
        }
    }

    @Override
    public ParComponent newComponent(final int nodeId) {
        return new ParComponent(nodeId);
    }

    @Override
    public ParEdge newEdge(final ParComponent from, final ParComponent to, final double weight) {
        return new ParEdge(from, to, weight);
    }
}

package edu.rice.comp322.boruvka.parallel;

import edu.rice.comp322.boruvka.Component;
import edu.rice.comp322.boruvka.Edge;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.locks.ReentrantLock;

/**
 * This class may be modified.
 *
 * @author <a href="http://shams.web.rice.edu/">Shams Imam</a> (shams@rice.edu)
 */
public final class ParComponent extends Component<ParComponent> {

    public final int nodeId;
    public List<Edge<ParComponent>> pq = new ArrayList<>();
    public double totalWeight = 0;
    public long totalEdges = 0;
    public volatile boolean isDead = false;
    public final ReentrantLock lock = new ReentrantLock();


    protected ParComponent(final int nodeId) {
        super();
        this.nodeId = nodeId;
    }

    @Override
    public int nodeId() {
        return nodeId;
    }

    @Override
    public double totalWeight() {
        return totalWeight;
    }

    @Override
    public long totalEdges() {
        return totalEdges;
    }

    /**
     * insert edge in weight order.
     */
    public void addEdge(final Edge<ParComponent> e) {
        // insert edge in weight order
        int i = 0;
        while (i < pq.size()) {
            if (e.weight() < pq.get(i++).weight()) {
                i--;
                break;
            }
        }
        pq.add(i, e);
    }

    /**
     * Get the edge with minimum weight from the sorted list pq.
     */
    public Edge<ParComponent> getMinEdge() {
        for (int i = 0; i < pq.size(); i++) {
            final Edge<ParComponent> e = pq.get(i);
            if (e.fromComponent() != e.toComponent()) {
                return e;
            }
        }
        return null;
    }

    /**
     * Merge two components together, connected by an edge with weight edgeWeight.
     */
    public void merge(final ParComponent other, final double edgeWeight) {
        totalWeight += other.totalWeight + edgeWeight;
        totalEdges += other.totalEdges + 1;
        final List<Edge<ParComponent>> npq = new ArrayList<>();
        int i = 0;
        int j = 0;
        while (i + j < pq.size() + other.pq.size()) {
            // get rid of inter-component edges
            while (i < pq.size()) {
                final Edge<ParComponent> e = pq.get(i);
                if ((e.fromComponent() != this && e.fromComponent() != other) || (e.toComponent() != this && e.toComponent() != other)) {
                    break;
                }
                i++;
            }
            while (j < other.pq.size()) {
                final Edge<ParComponent> e = other.pq.get(j);
                if ((e.fromComponent() != this && e.fromComponent() != other) || (e.toComponent() != this && e.toComponent() != other)) {
                    break;
                }
                j++;
            }
            if (j < other.pq.size() && (i >= pq.size() || pq.get(i).weight() > other.pq.get(j).weight())) {
                npq.add(other.pq.get(j++).replaceComponent(other, this));
            } else if (i < pq.size()) {
                npq.add(pq.get(i++).replaceComponent(other, this));
            }
        }
        other.pq.clear();
        pq.clear();
        pq = npq;
    }

    @Override
    public boolean equals(final Object o) {
        if (this == o) {
            return true;
        }
        if (!(o instanceof Component)) {
            return false;
        }

        final Component component = (Component) o;

        if (nodeId != component.nodeId()) {
            return false;
        }

        return true;
    }

    @Override
    public int hashCode() {
        return nodeId;
    }

    @Override
    public String toString() {
        return "ParComponent{" +
                "nodeId=" + nodeId +
                ", pq.size=" + pq.size() +
                ", isDead=" + isDead +
                '}';
    }
}

package edu.rice.comp322.boruvka.parallel;

import edu.rice.comp322.boruvka.Edge;

/**
 * This class may be modified.
 *
 * @author <a href="http://shams.web.rice.edu/">Shams Imam</a> (shams@rice.edu)
 */
public final class ParEdge extends Edge<ParComponent> implements Comparable<Edge> {

    protected volatile ParComponent fromComponent;
    protected volatile ParComponent toComponent;
    public double weight;

    protected ParEdge(final ParComponent from, final ParComponent to, final double w) {
        fromComponent = from;
        toComponent = to;
        weight = w;
    }

    @Override
    public ParComponent fromComponent() {
        return fromComponent;
    }

    @Override
    public ParComponent toComponent() {
        return toComponent;
    }

    @Override
    public double weight() {
        return weight;
    }

    /**
     * Given one member of this edge, return the other.
     */
    public ParComponent getOther(final ParComponent from) {
        if (fromComponent == from) {
            assert (toComponent != from);
            return toComponent;
        }

        if (toComponent == from) {
            assert (fromComponent != from);
            return fromComponent;
        }
        assert (false);
        return null;

    }

    @Override
    public int compareTo(final Edge e) {
        if (e.weight() == weight) {
            return 0;
        } else if (weight < e.weight()) {
            return -1;
        } else {
            return 1;
        }
    }

    /**
     * Given one member of this edge, swap it out for a different component.
     */
    public synchronized ParEdge replaceComponent(final ParComponent from, final ParComponent to) {
        if (fromComponent == from) {
            fromComponent = to;
        }
        if (toComponent == from) {
            toComponent = to;
        }
        return this;
    }
}
